// Function node (NOT Function Item)

// stable hash
function hashKey(title, company, url) {
  const s = (title || '') + '|' + (company || '') + '|' + (url || '');
  let h = 5381; 
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h) + s.charCodeAt(i);
  return (h >>> 0).toString(16);
}

// ban list
const BAN = [/no\s+(?:visa\s+)?sponsorship/i,
  /must\s+be\s+(?:legally\s+)?authorized/i,
  /we\s+do\s+not\s+(?:offer|provide)\s+sponsorship/i,
  /candidates?\s+must\s+have\s+.*\s+work\s+(?:permit|authorization)/i,

];

const input = $input.all();
const seen = new Set();
const out = [];

for (let i = 0; i < input.length; i++) {
  const src = input[i];
  const j = { ...(src.json || {}) }; // shallow clone

  // ban check
  const hay = ((j.title || '') + ' ' + (j.raw_description || '')).toLowerCase();
  if (BAN.some(re => re.test(hay))) continue;

  // dedupe
  const k = hashKey(
    (j.title || '').toLowerCase(),
    (j.company || '').toLowerCase(),
    (j.url || '').toLowerCase()
  );
  if (seen.has(k)) continue;
  seen.add(k);

  j.hash = k;

  // preserve pairing so downstream nodes don't complain
  out.push({
    json: j,
    pairedItem: { item: i }
  });
}

return out;

// === Prepare compact prompt input for the AI scoring agent ===

// Fetch your CV text from the earlier node
// (Change 'MapResume' to your actual node name that contains cv_text)
const cv_text = $('MapResume').item.json.cv_text;

const job = $json;

// limit long job text to avoid token waste
const maxDesc = 5000; // ~1000 words
const cleanDesc = (job.raw_description || '')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, maxDesc);

// build a structured summary text block for LLM
const jobTextBlock = [
  `Job title: ${job.title || ''}`,
  `Company: ${job.company || ''}`,
  job.location ? `Location: ${job.location}` : '',
  job.seniority_level ? `Seniority: ${job.seniority_level}` : '',
  job.employment_type ? `Employment type: ${job.employment_type}` : '',
  job.industries ? `Industry: ${job.industries}` : '',
  job.job_function ? `Function: ${job.job_function}` : '',
  '',
  'Job Description:',
  cleanDesc,
].filter(Boolean).join('\n');

// return one item per job
return {
  job_text: jobTextBlock,
  cv_text: cv_text.slice(0, 10000), // safety cap
  job_meta: {
    title: job.title || '',
    company: job.company || '',
    url: job.url || job.apply_url || '',
    hash: job.hash || '',
    location: job.location || '',
    posted_at: job.posted_at || '',
    source: job.source || 'LinkedIn',
    pre_score:        job.preScore,          // 加这行
    pre_score_reasons: job.preScoreReasons,
  }
};

let raw;

// 1) Extract raw model output
if (typeof $json.output === 'string') {
  raw = $json.output;
} else if ($json.choices?.[0]?.message?.content) {
  raw = $json.choices[0].message.content;
} else if (typeof $json.text === 'string') {
  raw = $json.text;
} else {
  raw = JSON.stringify($json);
}

raw = String(raw).trim();
raw = raw.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();

// 2) Parse JSON safely
let data;
try {
  data = JSON.parse(raw);
} catch (e) {
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) {
    try {
      data = JSON.parse(m[0]);
    } catch (e2) {
      data = {
        parse_error: e2.message,
        raw
      };
    }
  } else {
    data = {
      parse_error: e.message,
      raw
    };
  }
}

// 3) Normalize score structure
if (!data || typeof data !== 'object') {
  data = {};
}

if (!data.score || typeof data.score !== 'object') {
  data.score = {};
}

const score = data.score;

score.background_match = Number(score.background_match) || 0;
score.skills_overlap = Number(score.skills_overlap) || 0;
score.experience_relevance = Number(score.experience_relevance) || 0;
score.seniority = Number(score.seniority) || 0;
score.language_requirement = Number(score.language_requirement) || 0;
score.company_score = Number(score.company_score) || 0;

// Always recalculate overall to ensure consistency
score.overall =
  score.background_match +
  score.skills_overlap +
  score.experience_relevance +
  score.seniority +
  score.language_requirement +
  score.company_score;

// 4) Normalize other fields
data.summary = typeof data.summary === 'string' ? data.summary : 'No summary available';
data.keywords = Array.isArray(data.keywords) ? data.keywords : [];
data.fit_bullets = Array.isArray(data.fit_bullets) ? data.fit_bullets : [];
data.connector = typeof data.connector === 'string' ? data.connector : 'No connector available';

// 5) Recover job_meta
let job_meta = {};

if ($json.job_meta) {
  job_meta = $json.job_meta;
} else if ($input.item?.json?.job_meta) {
  job_meta = $input.item.json.job_meta;
} else {
  try {
    job_meta = $('Prepare AI Input').item.json.job_meta || {};
  } catch (e) {
    job_meta = {};
  }
}

// 6) Return flattened structure
return {
  ...data,
  job_meta
};

const config = $('Config').item.json;
const keywords = JSON.parse(config.keywords);
const location = encodeURIComponent(config.location);
const altLocation = encodeURIComponent(config.alternativeLocation);
const geoId = config.geoId;
const filters = config.jobFilters;
const altFilters = config.alternativeJobFilters;

// Add time filter parameter (defaults to past 24 hours)
const timeFilter = config.timeFilter || 'r86400'; // r86400 = past 24 hours

const urls = keywords.map((kw, idx) => {
  const encodedKw = encodeURIComponent(kw);
  const loc = idx < 3 ? location : altLocation;
  const filter = idx < 3 ? filters : altFilters;

  return `https://www.linkedin.com/jobs/search?keywords=${encodedKw}&location=${loc}&f_TPR=${timeFilter}&position=1&pageNum=0`;
});

return [{
  json: {
    count: 100,
    scrapeCompany: true,
    urls: urls
  }
}];

// ---------- Read config ----------
const cfg = $('Config').first().json;

function parseArray(v) {
  if (Array.isArray(v)) return v;
  if (typeof v === 'string') {
    try {
      const parsed = JSON.parse(v);
      return Array.isArray(parsed) ? parsed : [parsed];
    } catch {
      return [v];
    }
  }
  return [];
}

const keywords = parseArray(cfg.keywords).map(s => String(s).toLowerCase().trim()).filter(Boolean);
const preferLanguages = parseArray(cfg.preferLanguages).map(s => String(s).toLowerCase().trim()).filter(Boolean);
const locationPref = String(cfg.location || '').toLowerCase().trim();
const seniorityPref = String(cfg.seniorityPreference || '').toLowerCase().trim();

// ---------- Dictionaries ----------
const LOCATION_MAP = {
  europe: [
    'europe', 'eu', 'european',
    'germany', 'france', 'netherlands', 'sweden', 'denmark',
    'belgium', 'spain', 'italy', 'ireland', 'poland',
    'portugal', 'finland', 'norway', 'austria', 'switzerland',
    'czech republic', 'czechia', 'hungary', 'romania', 'greece',
    'luxembourg', 'estonia', 'latvia', 'lithuania', 'slovakia',
    'slovenia', 'croatia', 'bulgaria'
  ],
  uk: ['uk', 'united kingdom', 'england', 'scotland', 'wales', 'northern ireland', 'britain'],
  north_america: ['north america', 'usa', 'united states', 'canada'],
};

const LANGUAGE_MAP = {
  english: ['english'],
  french: ['french', 'français', 'francais'],
  german: ['german', 'deutsch'],
  dutch: ['dutch', 'nederlands'],
  spanish: ['spanish', 'español', 'espanol'],
  italian: ['italian', 'italiano'],
  portuguese: ['portuguese', 'português', 'portugues'],
};

const SENIORITY_RULES = {
 junior: {
 positive: [
 /\bjunior\b/,
 /\bentry[- ]level\b/,
 /\bgraduate\b/,
 /\bnew grad\b/,
 /\bearly career\b/
 ],
 negative: [
 /\bsenior\b/,
 /\blead\b/,
 /\bprincipal\b/,
 /\bstaff\b/,
 /\bmanager\b/,
 /\bdirector\b/,
 /\bhead of\b/
 ],
 negativeYears: [
 /\b[5-9]\+?\s+years\b/,
 /\b10\+?\s+years\b/,
 /\b[5-9]\s*-\s*[9]\s+years\b/,
 /\b[6-9]\s*-\s*1[0-9]\s+years\b/
 ]
 },
 'mid-level': {
 positive: [
 /\bmid[- ]level\b/,
 /\bintermediate\b/,
 /\bassociate\b/,
 /\b2[- ]?4\s+years\b/,
 /\b3[- ]?5\s+years\b/
 ],
 negative: [
 /\bprincipal\b/,
 /\bstaff\b/,
 /\bdirector\b/,
 /\bhead of\b/
 ],
 negativeYears: [
 /\b8\+?\s+years\b/,
 /\b10\+?\s+years\b/
 ]
 },
 senior: {
 positive: [
 /\bsenior\b/,
 /\blead\b/,
 /\bprincipal\b/,
 /\bstaff\b/
 ],
 negative: [
 /\bintern\b/,
 /\binternship\b/,
 /\bgraduate\b/,
 /\bentry[- ]level\b/,
 /\bjunior\b/
 ],
 negativeYears: []
 }
};

// ---------- Regex packs ----------
const VISA_POSITIVE_RE = /visa sponsorship|sponsorship available|we sponsor|offer sponsorship|provide sponsorship|work visa|visa support|relocation support|immigration support|sponsor visa|will sponsor/i;

const VISA_NEGATIVE_RE = /no\s+(?:visa\s+)?sponsorship|must\s+be\s+(?:legally\s+)?authorized|do\s+not\s+(?:offer|provide)\s+sponsorship|cannot\s+(?:offer|provide)\s+(?:visa\s+)?sponsorship|sponsorship\s+(?:is\s+)?not\s+(?:available|provided|offered)|without\s+visa\s+sponsorship/i;

// If English is preferred, penalize explicit non-English requirements
const NON_ENGLISH_REQUIRED_RE = /\bfrench\b.*\brequired\b|\brequired\b.*\bfrench\b|\bgerman\b.*\brequired\b|\brequired\b.*\bgerman\b|\bdeutsch\b.*\berforderlich\b|\berforderlich\b.*\bdeutsch\b|\bspanish\b.*\brequired\b|\brequired\b.*\bspanish\b|\bitalian\b.*\brequired\b|\brequired\b.*\bitalian\b|\bdutch\b.*\brequired\b|\brequired\b.*\bdutch\b/i;

// ---------- Main ----------
const input = $input.all();
const out = [];

for (let i = 0; i < input.length; i++) {
  const src = input[i];
  const j = { ...(src.json || {}) };

  const title = String(j.title || '').toLowerCase();
  const company = String(j.company || '').toLowerCase();
  const desc = String(j.raw_description || '').toLowerCase();
  const jobLocation = String(j.location || '').toLowerCase();

  // Rules matching text: exclude company to avoid false triggers
  const hay = `${title} ${desc} ${jobLocation}`.toLowerCase();

  // Wider matching text for keywords
  const hayFull = `${title} ${company} ${desc} ${jobLocation}`.toLowerCase();

  let preScore = 0;
  const reasons = [];

  // ---------- 1) Keywords: max 9 ----------

let keywordPoints = 0;

for (const kw of keywords) {
 if (!kw) continue;

 if (hayFull.includes(kw)) {
 keywordPoints += 3;
 reasons.push(`keyword matched: ${kw}`);
 continue;
 }

 const tokens = kw.split(/\s+/).filter(Boolean);
 const hitCount = tokens.filter(t => hayFull.includes(t)).length;

 if (tokens.length > 1 && hitCount >= Math.ceil(tokens.length * 0.6)) {
 keywordPoints += 2;
 reasons.push(`keyword partial matched: ${kw}`);
 }
}

preScore += Math.min(keywordPoints, 9);


  // ---------- 2) Location: max 3 ----------
  // remote is always treated as a positive signal
  if (locationPref) {
    const locationTerms = LOCATION_MAP[locationPref] || [locationPref];

    if (
      locationTerms.some(term => hay.includes(term)) ||
      hay.includes('remote')
    ) {
      preScore += 3;
      reasons.push(`location matched: ${locationPref} or remote`);
    }
  } else if (hay.includes('remote')) {
    preScore += 3;
    reasons.push('location matched: remote');
  }

  // ---------- 3) Language: max +2 / penalty -3 ----------
  if (preferLanguages.length > 0) {
    if (preferLanguages.includes('english')) {
      if (NON_ENGLISH_REQUIRED_RE.test(hay)) {
        preScore -= 3;
        reasons.push('language penalty: non-english required');
      } else {
        preScore += 2;
        reasons.push('language assumed: english/default');
      }
    } else {
      let matchedLanguage = false;

      for (const lang of preferLanguages) {
        const langTerms = LANGUAGE_MAP[lang] || [lang];

        if (langTerms.some(term => hay.includes(term))) {
          preScore += 2;
          reasons.push(`language matched: ${lang}`);
          matchedLanguage = true;
          break;
        }
      }

      if (!matchedLanguage) {
        reasons.push('language not explicitly mentioned');
      }
    }
  }

  // ---------- 4) Seniority: +3 / -4 / -3 ----------
  if (seniorityPref && SENIORITY_RULES[seniorityPref]) {
    const rules = SENIORITY_RULES[seniorityPref];

    if (rules.positive.some(re => re.test(hay))) {
      preScore += 3;
      reasons.push(`seniority matched: ${seniorityPref}`);
    }

    if (rules.negative.some(re => re.test(hay))) {
      preScore -= 4;
      reasons.push(`seniority penalty: not ${seniorityPref}`);
    }

    if (rules.negativeYears.some(re => re.test(hay))) {
      preScore -= 3;
      reasons.push('experience penalty: years too high');
    }
  }

  // ---------- 5) Visa sponsorship: +4 / -8 ----------
  if (VISA_POSITIVE_RE.test(hay)) {
    preScore += 4;
    reasons.push('visa sponsorship signal found');
  }

  if (VISA_NEGATIVE_RE.test(hay)) {
    preScore -= 8;
    reasons.push('visa sponsorship negative signal found');
  }

  // ---------- Save score ----------
  j.preScore = preScore;
  j.preScoreReasons = reasons;

  // ---------- Threshold ----------
  if (preScore >= 6) {
    out.push({
      json: j,
      pairedItem: { item: i }
    });
  }
}

return out;
